import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import AIWorkflowAutomationServicesPage from "@screens/ai-screens/ai-workflow-automation-services";

const AIWorkflowAutomationServices = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "AI Workflow Automation Services", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.hire3dDesignerImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const validFaq = data?.allFaqJson?.nodes[0].faqs;
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "AI Workflow Automation Services to streamline business processes, reduce manual tasks, improve efficiency, and boost productivity.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1671",
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How to make AI automation workflow?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Start by finding tasks that are repeated daily. Map each step clearly. Choose a simple AI tool, connect your apps, test the flow, and improve it step by step.",
            },
          },
          {
            "@type": "Question",
            name: "What is the best AI workflow automation tool?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The best tool depends on your needs. Popular choices include Zapier, Make, and UiPath. Pick one that fits your budget, team size, and task type.",
            },
          },
          {
            "@type": "Question",
            name: "Can AI be used for workflow automation?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, AI can handle tasks like data entry, email replies, reports, and customer support. It saves time and reduces manual work.",
            },
          },
        ],
      },
    ],
  };
  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <AIWorkflowAutomationServicesPage db={db} faq={validFaq} />
      </main>
    </Layout_v2>
  );
};

export default AIWorkflowAutomationServices;
export const queryData = graphql`
  query MyQuery {
    hire3dDesignerImg: file(
      relativePath: { eq: "ai-workflow-automation-services.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "ai-workflow-automation-services" } }) {
      nodes {
        metaTitle
        title
        slug
        description
      }
    }
    allFaqJson(filter: { slug: { eq: "ai-workflow-automation-services" } }) {
      nodes {
        slug
        faqs {
          question
          answer
          status
        }
      }
    }
  }
`;
